local Setting = {}
local PlayerDataCache = {}
local Date = ""
local SecondsLeft = 86400
local LastTime = os.time()

ExchangeHelper = {}

local function syncExchangeTodayInfo(player)
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        return
    end
    local builder = DataBuilder.new()
    builder:addParam("secondsLeft", SecondsLeft)
    builder:addParam("gameTimeToday", cache.gameTimeToday)
    PacketSender:sendLuaCommonData(player.rakssid, "ExchangeTodayInfo", builder:getData())
end

local function sendReceiveResult(player, code, result, message)
    local data = {}
    data.code = code
    data.data = {}
    data.message = message or "success"
    if code == 1 then
        syncExchangeTodayInfo(player)
        for _, item in pairs(result) do
            table.insert(data.data, item.scrapId)
        end
    end
    PacketSender:sendLuaCommonData(player.rakssid, "ExchangeReceiveResult", json.encode(data))
end

---领取集换卡片，抽卡片
local function onPlayerReceive(player, boxId)
    local setting = Setting[boxId]
    if not setting then
        LogUtil.log("[ExchangeHelper.onPlayerReceive] no setting. id=" .. boxId, LogUtil.LogLevel.Error)
        sendReceiveResult(player, 1001, {}, "can not find setting. id=" .. boxId)
        return
    end
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        LogUtil.log("[ExchangeHelper.onPlayerReceive] no cache.", LogUtil.LogLevel.Error)
        sendReceiveResult(player, 1002, {}, "can not find player db cache.")
        return
    end
    if cache.gameTimeToday < setting then
        LogUtil.log("[ExchangeHelper.onPlayerReceive] not enough game time. data=" .. json.encode(cache), LogUtil.LogLevel.Error)
        sendReceiveResult(player, 1004, {}, "not enough game time. id=" .. boxId)
        return
    end
    ---调用领取接口，领取成功后给客户端发消息
    WebService:OpenExchangeBox(player.userId, boxId, function(result, code, message)
        if not player:checkReady() then
            return
        end
        if code ~= 1 then
            sendReceiveResult(player, code, result, message)
        else
            sendReceiveResult(player, code, result, message)
        end
    end)
end

local function initConfig(time)
    time = time or 0
    WebService:GetExchangeConfig(function(data)
        Date = data.date or Date
        SecondsLeft = data.secondsLeft or 86400
        Setting = {}
        for _, item in pairs(data.boxInfo or {}) do
            Setting[item.uuid] = item.duration * 60
        end
        if TableUtil.getTableSize(Setting) == 0 then
            return
        end
        for userId, cache in pairs(PlayerDataCache) do
            cache.gameTimeToday = time
        end
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            syncExchangeTodayInfo(player)
        end
    end)
end

function ExchangeHelper:init()
    initConfig()
    CommonDataEvents:registerCallBack("ExchangeReceive", function(userId, data)
        local player = PlayerManager:getPlayerByUserId(userId)
        if not player then
            return
        end
        onPlayerReceive(player, data)
    end)
end

function ExchangeHelper:onPlayerLogin(player)
    if TableUtil.getTableSize(Setting) == 0 then
        return
    end
    if PlayerManager:isAIPlayer(player) then
        return
    end
    local userId = player.userId
    WebService:GetPlayTime(userId, function(data)
        local _player = PlayerManager:getPlayerByUserId(userId)
        if not _player then
            return
        end
        if data.date ~= Date then
            data.playSecond = 0
        end
        local cache = { dayKey = Date, gameTimeToday = data.playSecond }
        PlayerDataCache[tostring(_player.userId)] = cache
        syncExchangeTodayInfo(_player)
    end)
end

function ExchangeHelper:onPlayerReady(player)
    if TableUtil.getTableSize(Setting) == 0 then
        return
    end
    if PlayerManager:isAIPlayer(player) then
        return
    end
    ---TODO  reward
    ExchangeHelper:receiveExchangeProps(player)
end

function ExchangeHelper:updatePlayerGameTime()
    if SecondsLeft <= 0 then
        return
    end
    local curTime = os.time()
    local time = curTime - LastTime
    LastTime = curTime
    if SecondsLeft > 0 then
        SecondsLeft = SecondsLeft - time
    end
    for _, cache in pairs(PlayerDataCache) do
        cache.gameTimeToday = cache.gameTimeToday + time
    end
    if SecondsLeft == 0 then
        for _, cache in pairs(PlayerDataCache) do
            cache.gameTimeToday = 0
        end
        local random = HostApi.random(10, 250)
        LuaTimer:schedule(function()
            initConfig(random)
        end, random * 1000)
    end
end

function ExchangeHelper:onPlayerLogout(userId)
    local cache = PlayerDataCache[tostring(userId)]
    if not cache then
        return
    end
    WebService:SetPlayTime(userId, cache.gameTimeToday)
    PlayerDataCache[tostring(userId)] = nil
end

---增加玩家游戏时长(GM)
function ExchangeHelper:addGameTime(player, seconds)
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        return
    end
    cache.gameTimeToday = cache.gameTimeToday + seconds
    syncExchangeTodayInfo(player)
end

---尝试领取当天集换卡片，抽卡片(GM)
function ExchangeHelper:receiveExchange(player)
    local cache = PlayerDataCache[tostring(player.userId)]
    if not cache then
        return
    end
    for boxId, setting in pairs(Setting) do
        if cache.gameTimeToday >= setting then
            onPlayerReceive(player, boxId)
        end
    end
end

---添加集换特权道具(GM)
function ExchangeHelper:addExchangeProps(player, propsId, propsCount, expiryTime)
    WebService:SetExchangeProp(player.userId, propsId, propsCount, expiryTime)
end

local function consumeExchangeProps(player, item)
    local params = StringUtil.split(item.gamePropsId, ":")
    if #params ~= 2 then
        return
    end
    local time = os.time()
    local propsType = params[1]
    local propsId = params[2]
    if item.expire == 0 then
        CommonReceiveRewardEvent:invoke(player, propsType, propsId, item.propsAmount, 0)
    else
        if item.expire - time > 0 then
            CommonReceiveRewardEvent:invoke(player, propsType, propsId, item.propsAmount, item.expire - time)
        end
    end
end

---领取集换特权道具
function ExchangeHelper:receiveExchangeProps(player)
    if not CommonReceiveRewardEvent:hasSubscriber() then
        return
    end
    local userId = player.userId
    WebService:GetExchangeProp(userId, function(data)
        local player1 = PlayerManager:getPlayerByUserId(userId)
        if not player1 then
            return
        end
        local propsIds = {}
        for _, item in pairs(data) do
            if item.expire == nil or item.expire == "" then
                item.expire = "0"
            end
            if item.propsAmount == nil or item.propsAmount == "" then
                item.propsAmount = "1"
            end
            item.expire = math.floor(tonumber(item.expire))
            item.propsAmount = tonumber(item.propsAmount)
            propsIds[item.gamePropsId] = true
        end
        for propsId, _ in pairs(propsIds) do
            WebService:ConsumeExchangeProp(userId, propsId, function()
                local player2 = PlayerManager:getPlayerByUserId(userId)
                if not player2 then
                    return
                end
                for _, item in pairs(data) do
                    if item.gamePropsId == propsId then
                        consumeExchangeProps(player2, item)
                    end
                end
            end)
        end
    end)
end